import { useEffect, useRef, useState, useCallback } from 'react';
import { Client } from '@stomp/stompjs';
import SockJS from 'sockjs-client';

const WS_URL = process.env.REACT_APP_WS_URL || 'http://localhost:8080/ws';

/**
 * Custom hook that manages the STOMP WebSocket connection and chat state.
 *
 * @param {string|null} roomId  - The room to subscribe to
 * @param {string}      userId  - The current user's ID (used as senderId)
 */
export default function useChat(roomId, userId) {
  const [messages, setMessages] = useState([]);
  const [connected, setConnected] = useState(false);
  const [partnerTyping, setPartnerTyping] = useState(false);
  const clientRef = useRef(null);
  const typingTimerRef = useRef(null);

  // Connect / reconnect when roomId changes
  useEffect(() => {
    if (!roomId) return;

    const client = new Client({
      webSocketFactory: () => new SockJS(WS_URL),
      reconnectDelay: 3000,
      onConnect: () => {
        setConnected(true);
        // Subscribe to room topic
        client.subscribe(`/topic/chat/${roomId}`, (frame) => {
          const payload = JSON.parse(frame.body);

          if (payload.type === 'TYPING') {
            if (payload.senderId !== userId) {
              setPartnerTyping(true);
              clearTimeout(typingTimerRef.current);
              typingTimerRef.current = setTimeout(() => setPartnerTyping(false), 2000);
            }
            return;
          }

          setMessages((prev) => [...prev, payload]);
        });
      },
      onDisconnect: () => setConnected(false),
      onStompError: (frame) => console.error('STOMP error', frame),
    });

    client.activate();
    clientRef.current = client;

    return () => {
      client.deactivate();
      setConnected(false);
      setMessages([]);
    };
  }, [roomId, userId]);

  /** Send a chat message */
  const sendMessage = useCallback((text) => {
    if (!clientRef.current?.connected || !roomId) return;
    clientRef.current.publish({
      destination: '/app/sendMessage',
      body: JSON.stringify({
        senderId: userId,
        roomId,
        message: text,
        timestamp: new Date().toISOString(),
        type: 'CHAT',
      }),
    });
  }, [roomId, userId]);

  /** Send a typing indicator */
  const sendTyping = useCallback(() => {
    if (!clientRef.current?.connected || !roomId) return;
    clientRef.current.publish({
      destination: '/app/typing',
      body: JSON.stringify({
        senderId: userId,
        roomId,
        message: '',
        type: 'TYPING',
      }),
    });
  }, [roomId, userId]);

  return { messages, connected, partnerTyping, sendMessage, sendTyping };
}
